// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';
// Import dữ liệu loài từ file bạn cung cấp
import speciesData from '../data/speciesData';

function WoodDetail() {
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');

  const [farmDetails, setFarmDetails] = useState(null);
  const [activities, setActivities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const [formData, setFormData] = useState({
    speciesName: '',      // Tên lâm sản cuối cùng
    scientificName: '',   // Tên khoa học cuối cùng
    date: '',
    quantity: 0,
    unit: '',
    type: '',
    reason: '',
    source: '',
    destination: '',
    verifiedBy: '',
  });

  const [selectedSpecies, setSelectedSpecies] = useState('');
  const [isManualEntry, setIsManualEntry] = useState(false);

  // Hàm fetchData không thay đổi
  const fetchData = useCallback(async () => {
    // ...
  }, [farmId, token]);

  useEffect(() => {
    // fetchData(); // Bạn có thể mở lại khi cần
    setLoading(false); // Tạm thời tắt loading để test form
  }, [fetchData]);

  // Hàm xử lý chung
  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };
  
  // Hàm xử lý dropdown Tên lâm sản
  const handleSpeciesSelectionChange = (e) => {
    const value = e.target.value;
    setSelectedSpecies(value);

    if (value === 'manual' || value === 'Nhập thủ công') {
      setIsManualEntry(true);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else if (value === '') {
      setIsManualEntry(false);
      setFormData(prev => ({ ...prev, speciesName: '', scientificName: '' }));
    } else {
      setIsManualEntry(false);
      const matched = speciesData.find(s => s.tenLamSan === value);
      if (matched) {
        setFormData(prev => ({
          ...prev,
          speciesName: matched.tenLamSan,
          scientificName: matched.tenKhoaHoc,
        }));
      }
    }
  };
  
  const handleAddActivity = async (e) => {
    e.preventDefault();
    // ... logic submit form ...
  };
  
  if (loading) return <div className="form-container"><p>Đang tải...</p></div>;
  
  return (
    <div className="form-container">
      <h2>👁️ Nhật ký hoạt động của cơ sở: {farmDetails?.tenCoSo || 'N/A'}</h2>
      
      <h3>Thêm bản ghi mới</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      
      <form onSubmit={handleAddActivity} className="modern-form">
        <div className="form-grid">
          
          <div className="form-group-full-width">
            <div className="form-grid">
              <div className="form-group">
                <label htmlFor="speciesSelection">Tên lâm sản:</label>
                <select 
                  id="speciesSelection"
                  value={selectedSpecies}
                  onChange={handleSpeciesSelectionChange} // <-- ĐÃ SỬA LỖI TYPO TẠI ĐÂY
                  required
                >
                  <option value="">-- Chọn hoặc nhập tay --</option>
                  {speciesData.map((species, index) => (
                    <option key={index} value={species.tenLamSan}>{species.tenLamSan}</option>
                  ))}
                  {/* Dòng "Nhập tay" có thể được thay thế bằng dòng "Nhập thủ công" trong file data */}
                </select>
              </div>

              {!isManualEntry && selectedSpecies && selectedSpecies !== 'manual' && selectedSpecies !== 'Nhập thủ công' && (
                <div className="form-group">
                  <label>Tên khoa học:</label>
                  <input type="text" value={formData.scientificName} readOnly disabled />
                </div>
              )}

              {isManualEntry && (
                <>
                  <div className="form-group">
                    <label htmlFor="speciesName">Tên lâm sản (nhập tay):</label>
                    <input type="text" name="speciesName" value={formData.speciesName} onChange={handleFormChange} required />
                  </div>
                  <div className="form-group">
                    <label htmlFor="scientificName">Tên khoa học (nhập tay):</label>
                    <input type="text" name="scientificName" value={formData.scientificName} onChange={handleFormChange} />
                  </div>
                </>
              )}
            </div>
          </div>
          
          {/* CÁC TRƯỜNG CÒN LẠI CỦA FORM */}
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input type="date" name="date" value={formData.date} onChange={handleFormChange} required />
          </div>
          {/* ... các trường còn lại của form ... */}
        </div>
        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>
    </div>
  );
}

export default WoodDetail;
